files.src/index.css:
@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply font-sans;
  }
}

@layer components {
  .glass-card {
    @apply bg-white/5 backdrop-blur-xl border border-white/10 shadow-2xl;
  }

  .input-field {
    @apply w-full px-4 py-3 bg-dark-900/50 border border-dark-700 rounded-lg 
           text-dark-100 placeholder-dark-400 
           transition-all duration-200 ease-out
           focus:outline-none focus:ring-2 focus:ring-primary-500/50 focus:border-primary-500
           hover:border-dark-600;
  }

  .btn-primary {
    @apply w-full px-4 py-3 bg-primary-600 hover:bg-primary-700 
           text-white font-medium rounded-lg
           transition-all duration-200 ease-out
           transform hover:scale-[1.02] active:scale-[0.98]
           focus:outline-none focus:ring-2 focus:ring-primary-500/50 focus:ring-offset-2 focus:ring-offset-dark-950
           shadow-lg shadow-primary-500/25;
  }

  .link-text {
    @apply text-primary-400 hover:text-primary-300 transition-colors duration-200;
  }
}

